func computeSearchTerms(db *sql.DB, asin, period string, minRank int) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT search_term, search_frequency_rank, asin_1, click_share_1, conversion_share_1, asin_2, click_share_2, conversion_share_2, asin_3, click_share_3, conversion_share_3, period FROM search_terms ORDER BY search_frequency_rank ASC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var term, a1, a2, a3, p sql.NullString
		var rank int
		var c1, v1, c2, v2, c3, v3 float64
		if err := rows.Scan(&term, &rank, &a1, &c1, &v1, &a2, &c2, &v2, &a3, &c3, &v3, &p); err != nil {
			return nil, err
		}
		if minRank > 0 && rank > minRank {
			continue
		}
		if period != "" && p.String != "" && !strings.EqualFold(period, p.String) {
			continue
		}
		yourASIN, click, conv, comp, compClick := pickASIN(asin, a1.String, c1, v1, a2.String, c2, v2, a3.String, c3, v3)
		if asin != "" && yourASIN == "" {
			continue
		}
		out = append(out, map[string]any{"search_term": term.String, "search_frequency_rank": rank, "your_asin": yourASIN, "your_click_share": click, "your_conversion_share": conv, "competitor_1_asin": comp, "competitor_1_click_share": compClick})
	}
	return out, rows.Err()
}

func computeMarketBasket(db *sql.DB, asin string) ([]map[string]any, error) {
	query := `SELECT your_asin, co_purchased_asin_1, combination_pct_1, co_purchased_asin_2, combination_pct_2, co_purchased_asin_3, combination_pct_3 FROM market_basket`
	args := []any{}
	if asin != "" {
		query += " WHERE your_asin=?"
		args = append(args, asin)
	}
	result, err := scanRowsMust(db.Query(query, args...))
	if err != nil {
		return nil, err
	}
	rows, ok := result.([]map[string]any)
	if !ok {
		return nil, nil
	}
	return rows, nil
}

func pickASIN(filter, a1 string, c1, v1 float64, a2 string, c2, v2 float64, a3 string, c3, v3 float64) (string, float64, float64, string, float64) {
	if filter == "" || filter == a1 {
		return a1, c1, v1, firstNonEmpty(a2, a3), firstNonZero(c2, c3)
	}
	if filter == a2 {
		return a2, c2, v2, firstNonEmpty(a1, a3), firstNonZero(c1, c3)
	}
	if filter == a3 {
		return a3, c3, v3, firstNonEmpty(a1, a2), firstNonZero(c1, c2)
	}
	return "", 0, 0, "", 0
}

func firstNonZero(values ...float64) float64 {
	for _, v := range values {
		if v != 0 {
			return v
		}
	}
	return 0
}
